<script setup lang="ts">
    import { PhHouse, PhFunnel, PhTimer, PhUser, PhListHeart, PhMagnifyingGlass, PhMicrophone } from "@phosphor-icons/vue";
    import { ref } from "vue";

    const ativo = ref<string>("inicio");

    const ativar = (item: string) => {
        ativo.value = item;
    }


    const texto = ref<string>("");

    const falar = () => {
        const SpeechRecognition =
        // eslint-disable-next-line @typescript-eslint/no-explicit-any
            (window as any).SpeechRecognition ||
            // eslint-disable-next-line @typescript-eslint/no-explicit-any
            (window as any).webkitSpeechRecognition;

        const recognition = new SpeechRecognition();

        recognition.lang = "pt-BR";
        recognition.interimResults = true;
        recognition.start();

        // eslint-disable-next-line @typescript-eslint/no-explicit-any
        recognition.onresult = (event: any) => {
            const fala = event.results[0][0].transcript;

            texto.value = fala;
        }
    }
</script>


